import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import axios from "axios";
import { ThumbsUp, MessageCircle, Share2, ArrowLeft, ChevronLeft, ChevronRight } from "lucide-react";
import { API_BASE_URL } from "../config/config";

// ─── Time ago ─────────────────────────────────────────────────────────────────
const timeAgo = (dateStr) => {
    if (!dateStr) return "";
    const diff = (Date.now() - new Date(dateStr)) / 1000;
    if (diff < 60) return "just now";
    if (diff < 3600) return `${Math.floor(diff / 60)}m ago`;
    if (diff < 86400) return `${Math.floor(diff / 3600)}h ago`;
    return `${Math.floor(diff / 86400)}d ago`;
};

// ─── Image Carousel ───────────────────────────────────────────────────────────
function ImageCarousel({ images }) {
    const [idx, setIdx] = useState(0);
    if (!images || images.length === 0) return null;

    const getImageSrc = (url) => {
        if (!url) return "";
        if (url.startsWith("http")) return url;
        return API_BASE_URL.replace(/\/$/, "") + url;
    };

    return (
        <div style={{ position: "relative", borderRadius: 12, overflow: "hidden", marginBottom: 16 }}>
            <img
                src={getImageSrc(images[idx])}
                alt={`post-${idx}`}
                style={{ width: "100%", maxHeight: 420, objectFit: "cover", display: "block" }}
            />
            {images.length > 1 && (
                <>
                    <button
                        onClick={() => setIdx((i) => (i - 1 + images.length) % images.length)}
                        style={{
                            position: "absolute", left: 10, top: "50%", transform: "translateY(-50%)",
                            background: "rgba(0,0,0,0.45)", border: "none", borderRadius: "50%",
                            width: 34, height: 34, display: "flex", alignItems: "center",
                            justifyContent: "center", cursor: "pointer", color: "#fff",
                        }}
                    ><ChevronLeft size={18} /></button>
                    <button
                        onClick={() => setIdx((i) => (i + 1) % images.length)}
                        style={{
                            position: "absolute", right: 10, top: "50%", transform: "translateY(-50%)",
                            background: "rgba(0,0,0,0.45)", border: "none", borderRadius: "50%",
                            width: 34, height: 34, display: "flex", alignItems: "center",
                            justifyContent: "center", cursor: "pointer", color: "#fff",
                        }}
                    ><ChevronRight size={18} /></button>
                    <div style={{
                        position: "absolute", bottom: 10, left: 0, right: 0,
                        display: "flex", justifyContent: "center", gap: 6,
                    }}>
                        {images.map((_, i) => (
                            <span key={i} onClick={() => setIdx(i)} style={{
                                width: 8, height: 8, borderRadius: "50%", cursor: "pointer",
                                background: i === idx ? "#fff" : "rgba(255,255,255,0.45)",
                                display: "inline-block",
                            }} />
                        ))}
                    </div>
                </>
            )}
        </div>
    );
}

// ─── PostDetail Page ──────────────────────────────────────────────────────────
export default function PostDetail() {
    const { id } = useParams();
    const navigate = useNavigate();
    const [post, setPost] = useState(null);
    const [loading, setLoading] = useState(true);
    const [notFound, setNotFound] = useState(false);
    const [copied, setCopied] = useState(false);

    const SOCIAL_API = API_BASE_URL + "api/user/socialpost/";

    // ─── Check if user is logged in ──────────────────────────────────────────
    const storedUsername = localStorage.getItem("SignatoryLoginData");
    const storedInvestor = localStorage.getItem("InvestorData");
    const isLoggedIn = !!(storedUsername || storedInvestor);

    useEffect(() => {
        fetchPost();
    }, [id]);

    const fetchPost = async () => {
        setLoading(true);
        try {
            const res = await axios.get(SOCIAL_API + `post/${id}`);
            if (res.data.success) {
                setPost(res.data.post);
            } else {
                setNotFound(true);
            }
        } catch (err) {
            setNotFound(true);
        } finally {
            setLoading(false);
        }
    };

    const handleCopyLink = async () => {
        try {
            await navigator.clipboard.writeText(window.location.href);
            setCopied(true);
            setTimeout(() => setCopied(false), 2000);
        } catch { }
    };

    // ── Loading ──
    if (loading) {
        return (
            <div style={{ minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center", background: "#f8f9fa" }}>
                <div className="text-center">
                    <div className="spinner-border text-danger" role="status" />
                    <p style={{ color: "#aaa", marginTop: 12, fontSize: "0.9rem" }}>Loading post...</p>
                </div>
            </div>
        );
    }

    // ── Not found ──
    if (notFound || !post) {
        return (
            <div style={{ minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center", background: "#f8f9fa" }}>
                <div className="text-center">
                    <div style={{ fontSize: "3rem", marginBottom: 12 }}>😕</div>
                    <h4 style={{ color: "#333", marginBottom: 8 }}>Post not found</h4>
                    <p style={{ color: "#aaa", fontSize: "0.9rem", marginBottom: 20 }}>
                        This post may have been deleted or is not available.
                    </p>
                    <button
                        onClick={() => navigate(-1)}
                        style={{
                            padding: "10px 24px", borderRadius: 10, border: "none",
                            background: "#ff3e43", color: "#fff", cursor: "pointer",
                            fontWeight: 600, fontSize: "0.9rem",
                        }}
                    >
                        Go Back
                    </button>
                </div>
            </div>
        );
    }

    return (
        <div style={{ minHeight: "100vh", background: "#f8f9fa", padding: "20px 0" }}>
            <div style={{ maxWidth: 620, margin: "0 auto", padding: "0 16px" }}>

                {/* ── Back button ── */}
                <button
                    onClick={() => navigate(-1)}
                    style={{
                        display: "flex", alignItems: "center", gap: 6,
                        background: "none", border: "none", cursor: "pointer",
                        color: "#666", fontSize: "0.85rem", marginBottom: 20,
                        padding: "8px 0",
                    }}
                >
                    <ArrowLeft size={16} /> Back
                </button>

                {/* ── Post card ── */}
                <div style={{
                    background: "#fff", borderRadius: 16,
                    boxShadow: "0 2px 16px rgba(0,0,0,0.08)",
                    padding: "20px 20px",
                }}>

                    {/* Header */}
                    <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 16 }}>
                        <div style={{
                            width: 46, height: 46, borderRadius: "50%",
                            overflow: "hidden", flexShrink: 0, position: "relative",
                            background: "#ff3e43",
                        }}>
                            {post.author_image ? (
                                <img
                                    src={post.author_image}
                                    alt="author"
                                    style={{ width: "100%", height: "100%", objectFit: "cover" }}
                                    onError={(e) => { e.target.style.display = "none"; }}
                                />
                            ) : (
                                <div style={{
                                    width: "100%", height: "100%",
                                    display: "flex", alignItems: "center", justifyContent: "center",
                                    color: "#fff", fontWeight: 700, fontSize: "1.1rem",
                                    textTransform: "uppercase",
                                }}>
                                    {(post.author_name || "?").charAt(0)}
                                </div>
                            )}
                        </div>
                        <div style={{ flex: 1 }}>
                            <div style={{ display: "flex", alignItems: "center", gap: 8, flexWrap: "wrap" }}>
                                <span style={{ fontWeight: 700, fontSize: "0.95rem", color: "#1a1a1a" }}>
                                    {post.author_name || "Unknown"}
                                </span>
                                {post.author_type === "investor" && (
                                    <span style={{
                                        fontSize: "0.65rem", fontWeight: 600,
                                        padding: "2px 8px", borderRadius: 20,
                                        background: "#e8f5e9", color: "#2e7d32",
                                        border: "1px solid #a5d6a7",
                                    }}>
                                        👤 Investor
                                    </span>
                                )}
                            </div>
                            <span style={{ fontSize: "0.75rem", color: "#aaa" }}>
                                {timeAgo(post.created_at)}
                            </span>
                        </div>
                    </div>

                    {/* Content */}
                    {post.content && (
                        <p style={{ fontSize: "0.92rem", lineHeight: 1.7, color: "#333", marginBottom: 16 }}>
                            {post.content}
                        </p>
                    )}

                    {/* Images */}
                    <ImageCarousel images={post.images || []} />

                    {/* Stats */}
                    <div style={{
                        display: "flex", alignItems: "center", gap: 20,
                        padding: "14px 0 0",
                        borderTop: "1px solid #f0f0f0",
                    }}>
                        <div style={{ display: "flex", alignItems: "center", gap: 6, color: "#6c757d", fontSize: "0.85rem" }}>
                            <ThumbsUp size={17} strokeWidth={1.5} />
                            <span>{post.likes || 0} likes</span>
                        </div>
                        <div style={{ display: "flex", alignItems: "center", gap: 6, color: "#6c757d", fontSize: "0.85rem" }}>
                            <MessageCircle size={17} strokeWidth={1.5} />
                            <span>{post.comments || 0} comments</span>
                        </div>
                        <div style={{ marginLeft: "auto" }}>
                            <button
                                onClick={handleCopyLink}
                                style={{
                                    display: "flex", alignItems: "center", gap: 6,
                                    padding: "7px 16px", borderRadius: 10, border: "none",
                                    background: copied ? "#4caf50" : "#ff3e43",
                                    color: "#fff", cursor: "pointer",
                                    fontWeight: 600, fontSize: "0.8rem",
                                    transition: "background 0.2s",
                                }}
                            >
                                <Share2 size={14} />
                                {copied ? "Copied!" : "Copy Link"}
                            </button>
                        </div>
                    </div>
                </div>

                {/* ── Login prompt — sirf non-logged users ke liye ── */}
                {!isLoggedIn && (
                    <div style={{
                        marginTop: 20, background: "#fff",
                        borderRadius: 16, padding: "20px",
                        boxShadow: "0 2px 16px rgba(0,0,0,0.06)",
                        textAlign: "center",
                    }}>
                        <p style={{ margin: 0, fontSize: "0.9rem", color: "#555" }}>
                            Want to like, comment or follow?
                        </p>
                        <div style={{ display: "flex", gap: 10, justifyContent: "center", marginTop: 12 }}>
                            <button
                                onClick={() => navigate("/user/login")}
                                style={{
                                    padding: "9px 24px", borderRadius: 10, border: "2px solid #ff3e43",
                                    background: "none", color: "#ff3e43",
                                    cursor: "pointer", fontWeight: 600, fontSize: "0.85rem",
                                }}
                            >
                                Login
                            </button>
                            <button
                                onClick={() => navigate("/user/register")}
                                style={{
                                    padding: "9px 24px", borderRadius: 10, border: "none",
                                    background: "#ff3e43", color: "#fff",
                                    cursor: "pointer", fontWeight: 600, fontSize: "0.85rem",
                                }}
                            >
                                Sign Up
                            </button>
                        </div>
                    </div>
                )}

            </div>
        </div>
    );
}